```cpp
/*
 *  Fibonacci – recursive version
 *  -------------------------------------------------
 *  The Fibonacci sequence is defined as:
 *      F(0) = 0
 *      F(1) = 1
 *      F(n) = F(n‑1) + F(n‑2)   for n ≥ 2
 *
 *  This program implements the definition directly with a
 *  recursive function.  Note that the naïve recursion has
 *  exponential running time (≈ φ^n) and is only practical
 *  for small values of n (e.g., n ≤ 30‑35).  For larger n
 *  you would normally use memoisation or an iterative approach.
 *
 *  Compile with:   g++ -std=c++17 -O2 -Wall fib_recursive.cpp -o fib
 */

#include <iostream>
#include <limits>

// Recursive Fibonacci function
long long fib(int n)
{
    if (n == 0) return 0;          // base case
    if (n == 1) return 1;          // base case

    // recursive step
    return fib(n - 1) + fib(n - 2);
}

int main()
{
    std::cout << "Enter the index n (non‑negative integer): ";

    int n;
    if (!(std::cin >> n)) {
        std::cerr << "Invalid input.\n";
        return 1;
    }

    if (n < 0) {
        std::cerr << "n must be non‑negative.\n";
        return 1;
    }

    // Guard against overflow of the result.
    // long long can hold values up to about F(92) before wrapping.
    const int MAX_SAFE_INDEX = 92;   // F(93) exceeds 2^63‑1
    if (n > MAX_SAFE_INDEX) {
        std::cerr << "Warning: result will overflow 64‑bit signed integer. [K
"
                  << "(max safe index is " << MAX_SAFE_INDEX << ")\n";
    }

    long long result = fib(n);
    std::cout << "Fibonacci(" << n << ") = " << result << '\n';

    return 0;
}
```

### How it works
1. **`fib(int n)`**  
   * Base cases: `n == 0` returns 0, `n == 1` returns 1.  
   * Recursive case: returns the sum of `fib(n‑1)` and `fib(n‑2)`.

2. **`main()`**  
   * Reads an integer from the user (with basic error checking).  
   * Checks that `n` is non‑negative.  
   * Calls `fib(n)` and prints the result.

### Sample run

```
Enter the index n (non‑negative integer): 10
Fibonacci(10) = 55
```

